import{_ as r,C as s,o,c as l,E as i,w as n,a as t,a0 as d}from"./chunks/framework.CkNTPv-z.js";const _=JSON.parse('{"title":"Finland Legal Rights","description":"Legal rights for transgender people in Finland","frontmatter":{"layout":"doc","title":"Finland Legal Rights","description":"Legal rights for transgender people in Finland"},"headers":[],"relativePath":"europe/finland/legal-rights.md","filePath":"europe/finland/legal-rights.md","lastUpdated":null}'),c={name:"europe/finland/legal-rights.md"};function h(g,e,m,p,u,f){const a=s("Badge");return o(),l("div",null,[i(a,{variant:"yellow"},{default:n(()=>[...e[0]||(e[0]=[t("Self-ID since 2023",-1)])]),_:1}),i(a,{variant:"green"},{default:n(()=>[...e[1]||(e[1]=[t("Hate Crime Protections",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-finland" tabindex="-1">Legal Rights in Finland <a class="header-anchor" href="#legal-rights-in-finland" aria-label="Permalink to &quot;Legal Rights in Finland&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Finland passed a landmark self-ID law that took effect in 2023, replacing the previous requirement for sterilisation or medical diagnosis. Adults can now change their legal gender by simply filing a declaration with the Digital and Population Data Services Agency. A short reflection period of 30 days applies, after which the change must be confirmed.</p><p>For minors aged 15-17, parental consent is required. Those under 15 need a doctor&#39;s statement confirming their gender identity is stable.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Name changes can be submitted alongside your gender recognition application through the Digital and Population Data Services Agency. There is a small administrative fee (approximately €50). The process takes 2-4 weeks.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Finland prohibits discrimination based on gender identity in:</p><ul><li><strong>Employment</strong>: Recruitment, working conditions, termination</li><li><strong>Goods and services</strong>: Healthcare, housing, banking</li><li><strong>Education</strong>: From primary to university</li><li><strong>Social benefits</strong>: Access to welfare and pensions</li></ul><p>The Non-Discrimination Ombudsman handles complaints and investigations.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Gender identity is explicitly recognised as a hate crime motivation under Finnish law. Courts can impose enhanced penalties for crimes motivated by transphobia. The police have specialised hate crime investigation units.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://trasek.fi/" target="_blank" rel="noreferrer">Trasek</a> — Trans rights advocacy and support</li><li><a href="https://seta.fi/" target="_blank" rel="noreferrer">Seta</a> — LGBTQ+ rights organisation</li><li><a href="https://syrijnta.fi/" target="_blank" rel="noreferrer">Non-Discrimination Ombudsman</a> — File discrimination complaints</li></ul>',14))])}const k=r(c,[["render",h]]);export{_ as __pageData,k as default};
